        <EmptyState
          icon={
            <svg className="w-8 h-8" fill="none" viewBox="[REDACTED_PHONE]" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M19 11H5m14 0a[REDACTED_PHONE]v6a[REDACTED_PHONE]H5a[REDACTED_PHONE]v-6a[REDACTED_PHONE]m14 0V9a[REDACTED_PHONE]M5 11V9a[REDACTED_PHONE]m0 0V5a[REDACTED_PHONE]h6a[REDACTED_PHONE]v2M7 7h10" />
            </svg>
          }
          title={search ? "Sin resultados" : "Sin categorías todavía"}
        />
      ) : (
        <div className="flex flex-wrap gap-2">
          {filtered.map(cat => (
